"use client"

import { useState, useEffect, useRef, useMemo } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { 
  Gauge, Zap, Radio, ShieldAlert, Activity, WifiOff, Palette, 
  Camera, CarFront, AlertTriangle, Loader2, Clock, MapPin, 
  Footprints, Navigation, CheckCircle2, Sparkles, Share2, Trophy
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection } from "firebase/firestore";
import { aiRunPerformanceSummary, type AiRunPerformanceSummaryOutput } from "@/ai/flows/ai-run-performance-summary";

function getDistance(lat1: number, lon1: number, lat2: number, lon2: number) {
  const R = 6371e3;
  const phi1 = (lat1 * Math.PI) / 180;
  const phi2 = (lat2 * Math.PI) / 180;
  const deltaPhi = ((lat2 - lat1) * Math.PI) / 180;
  const deltaLambda = ((lon2 - lon1) * Math.PI) / 180;
  const a = Math.sin(deltaPhi / 2) * Math.sin(deltaPhi / 2) + Math.cos(phi1) * Math.cos(phi2) * Math.sin(deltaLambda / 2) * Math.sin(deltaLambda / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
}

const MOCK_ALERTS = [
  { id: 1, type: "Radar", lat: 42.6629, lng: 21.1655, location: "Prishtinë, Qendër" },
  { id: 2, type: "Polici", lat: 42.215, lng: 21.125, location: "Autostrada, Ferizaj" },
  { id: 3, type: "Kontrollë", lat: 42.231, lng: 20.735, location: "Tranzit, Prizren" },
];

type SpeedoTheme = 'm3_modern' | 'rs_performance' | 'amg_performance' | 'porsche' | 'default';
type ReportType = 'Radar' | 'Polici' | 'Kontrollë';

export default function DashboardPage() {
  const { user } = useUser();
  const db = useFirestore();
  const [speed, setSpeed] = useState(0);
  const [isDriving, setIsDriving] = useState(false);
  const [peakSpeed, setPeakSpeed] = useState(0);
  const [hasGps, setHasGps] = useState(false);
  const [mounted, setMounted] = useState(false);
  const [theme, setTheme] = useState<SpeedoTheme>('m3_modern');
  const [isReporting, setIsReporting] = useState<ReportType | null>(null);
  const [tripTime, setTripTime] = useState(0);
  const [tripDistance, setTripDistance] = useState(0);
  const [brakeCount, setBrakeCount] = useState(0);
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [showSummary, setShowSummary] = useState(false);
  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [isGeneratingAi, setIsGeneratingAi] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const { toast } = useToast();
  const [currentCoords, setCurrentCoords] = useState<{ lat: number; lng: number } | null>(null);
  const lastPos = useRef<{ lat: number; lng: number; timestamp: number } | null>(null);
  const wakeLockRef = useRef<any>(null);

  const profileRef = useMemoFirebase(() => {
    if (!user || !db) return null;
    return doc(db, "users", user.uid);
  }, [user, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    let interval: NodeJS.Timeout;
    if (isDriving) {
      interval = setInterval(() => {
        setTripTime(prev => prev + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isDriving]);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const recordStatus = useMemo(() => {
    if (peakSpeed > 300) return "REKORD KOSOVE";
    if (peakSpeed > 240) return `REKORD NË ${profile?.city?.toUpperCase() || 'QYTET'}`;
    return null;
  }, [peakSpeed, profile?.city]);

  const nearestAlert = useMemo(() => {
    if (!currentCoords) return null;
    const alertsWithDist = MOCK_ALERTS.map(alert => ({
      ...alert,
      distance: getDistance(currentCoords.lat, currentCoords.lng, alert.lat, alert.lng)
    }));
    const nearby = alertsWithDist.filter(a => a.distance < 2000);
    if (nearby.length === 0) return null;
    return nearby.sort((a, b) => a.distance - b.distance)[0];
  }, [currentCoords]);

  useEffect(() => {
    const requestWakeLock = async () => {
      try {
        if ('wakeLock' in navigator && isDriving) {
          wakeLockRef.current = await (navigator as any).wakeLock.request('screen');
        }
      } catch (err: any) {}
    };
    const releaseWakeLock = async () => {
      if (wakeLockRef.current !== null) {
        try {
          await wakeLockRef.current.release();
          wakeLockRef.current = null;
        } catch (e) {}
      }
    };
    if (isDriving) requestWakeLock();
    else releaseWakeLock();
    return () => { releaseWakeLock(); };
  }, [isDriving]);

  useEffect(() => {
    let watchId: number;
    if (isDriving && mounted) {
      if (!navigator.geolocation) return;
      watchId = navigator.geolocation.watchPosition(
        (position) => {
          setHasGps(true);
          const { latitude, longitude } = position.coords;
          const timestamp = position.timestamp;
          setCurrentCoords({ lat: latitude, lng: longitude });
          
          let currentKmh = 0;
          const directMps = position.coords.speed;

          if (directMps !== null && directMps !== undefined && directMps >= 0) {
            currentKmh = Math.round(directMps * 3.6);
          } else if (lastPos.current) {
            const distance = getDistance(lastPos.current.lat, lastPos.current.lng, latitude, longitude);
            const timeDiff = (timestamp - lastPos.current.timestamp) / 1000;
            if (timeDiff > 0 && distance > 0.1) {
              currentKmh = Math.round((distance / timeDiff) * 3.6);
            }
          }

          if (currentKmh > 420) return;

          setSpeed(prev => {
            if (prev - currentKmh > 15 && currentKmh < prev) {
              setBrakeCount(b => b + 1);
            }
            return currentKmh;
          });

          if (currentKmh > peakSpeed) setPeakSpeed(currentKmh);

          if (lastPos.current) {
            const d = getDistance(lastPos.current.lat, lastPos.current.lng, latitude, longitude);
            setTripDistance(prev => prev + d);
          }

          lastPos.current = { lat: latitude, lng: longitude, timestamp };
        },
        (error) => {
          setHasGps(false);
          console.warn("GPS Status:", error.message);
        },
        { enableHighAccuracy: true, timeout: 5000, maximumAge: 0 }
      );
    } else {
      setSpeed(0);
      setHasGps(false);
      lastPos.current = null;
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [isDriving, peakSpeed, mounted]);

  const handleQuickReport = (type: ReportType) => {
    if (!db || !currentCoords) {
      toast({ variant: "destructive", title: "Gabim", description: "GPS duhet të jetë aktiv." });
      return;
    }
    setIsReporting(type);
    
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type,
      lat: currentCoords.lat,
      lng: currentCoords.lng,
      location: profile?.city || "Kosovo",
      createdAt: new Date().toISOString(),
      userId: user?.uid
    });

    setTimeout(() => {
      setIsReporting(null);
      toast({ title: "Raportimi u krye!", description: `${type} u regjistrua LIVE.` });
    }, 1000);
  };

  const cycleTheme = () => {
    const themes: SpeedoTheme[] = ['m3_modern', 'rs_performance', 'amg_performance', 'porsche', 'default'];
    const currentIndex = themes.indexOf(theme);
    const nextIndex = (currentIndex + 1) % themes.length;
    setTheme(themes[nextIndex]);
  };

  const handleSaveRun = () => {
    if (!user || !db || !profile) return;
    setIsSaving(true);

    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      city: profile.city || "Prishtinë",
      runType: "Top Speed",
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    // Ruaj në historikun e përdoruesit
    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);

    // Ruaj në koleksionin publik për ranking
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);
    
    toast({
      title: "Gara u ruajt!",
      description: "Ju jeni tani pjesë e rankingut të sotëm!",
    });
    
    setIsSaving(false);
    setShowSummary(false);
  };

  const generateAiAnalysis = async () => {
    if (!user || !profile) return;
    setIsGeneratingAi(true);
    try {
      const result = await aiRunPerformanceSummary({
        userId: user.uid,
        carModel: `${profile.carBrand} ${profile.carModel}`,
        modifications: profile.modifications,
        city: profile.city || "Prishtinë",
        runDate: new Date().toLocaleDateString('sq-AL'),
        topSpeed: peakSpeed,
      });
      setAiSummary(result.summary);
    } catch (e) {
      toast({ variant: "destructive", title: "Gabim në AI", description: "Dështoi gjenerimi i analizës." });
    } finally {
      setIsGeneratingAi(false);
    }
  };

  if (!mounted) return <div className="min-h-screen bg-background" />;

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden safe-bottom no-scrollbar">
      <div className="p-6 flex items-center justify-between z-20 shrink-0">
        <div className="flex items-center gap-2">
          {hasGps ? (
            <Activity className="w-4 h-4 text-accent animate-pulse" />
          ) : (
            <WifiOff className="w-4 h-4 text-destructive" />
          )}
          <span className={cn(
            "text-[10px] font-bold tracking-widest uppercase neon-text",
            hasGps ? "text-accent" : "text-muted-foreground"
          )}>
            GPS: {hasGps ? "AKTIV" : "DUKE PRITUR..."}
          </span>
        </div>
        
        <div className="flex items-center gap-3">
          <Button variant="outline" size="icon" onClick={cycleTheme} className="w-10 h-10 rounded-xl glass border-white/10">
            <Palette className="w-5 h-5 text-accent" />
          </Button>
          <Badge variant="outline" className="bg-red-500/10 border-red-500/20 text-red-500 text-[10px] font-bold">
            ANTI-CHEAT
          </Badge>
        </div>
      </div>

      <div className="px-6 mb-4 z-20 shrink-0">
        <div className="grid grid-cols-3 gap-2 bg-white/5 p-2 rounded-2xl border border-white/10 glass shadow-lg">
          <Button onClick={() => handleQuickReport('Radar')} disabled={!!isReporting} className="h-12 flex flex-col gap-0.5 rounded-xl bg-red-600/20 hover:bg-red-600/40 border border-red-500/30 text-white">
            <Camera className="w-4 h-4 text-red-500" />
            <span className="text-[8px] font-black italic">RADAR</span>
          </Button>
          <Button onClick={() => handleQuickReport('Polici')} disabled={!!isReporting} className="h-12 flex flex-col gap-0.5 rounded-xl bg-blue-600/20 hover:bg-blue-600/40 border border-blue-500/30 text-white">
            <ShieldAlert className="w-4 h-4 text-blue-500" />
            <span className="text-[8px] font-black italic">POLICI</span>
          </Button>
          <Button onClick={() => handleQuickReport('Kontrollë')} disabled={!!isReporting} className="h-12 flex flex-col gap-0.5 rounded-xl bg-zinc-800/40 hover:bg-zinc-800/60 border border-zinc-500/30 text-white">
            <CarFront className="w-4 h-4 text-zinc-400" />
            <span className="text-[8px] font-black italic">KONTROLLË</span>
          </Button>
        </div>
      </div>

      <div className="flex flex-col items-center justify-center relative px-6 py-4">
        <div className="relative w-full aspect-square flex items-center justify-center max-w-[320px]">
          {theme === 'm3_modern' && (
            <div className="w-full h-full relative flex items-center justify-center overflow-hidden rounded-[3rem] bg-black border border-white/5">
              <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(59,130,246,0.1)_0%,transparent_70%)]" />
              <div className="absolute inset-0 flex items-center justify-between px-6">
                <div className="flex flex-col gap-1 items-end">
                  {[...Array(18)].map((_, i) => (
                    <div key={i} className={cn("w-12 h-1 rounded-full skew-x-[-30deg] transition-all duration-300", (18 - i) * 15 <= speed ? "bg-blue-500 shadow-[0_0_12px_#3b82f6]" : "bg-white/5")} />
                  ))}
                </div>
                <div className="flex flex-col gap-1 items-start">
                  {[...Array(18)].map((_, i) => (
                    <div key={i} className={cn("w-12 h-1 rounded-full skew-x-[30deg] transition-all duration-300", (18 - i) * 15 <= speed ? (18 - i > 15 ? "bg-red-600 shadow-[0_0_12px_red]" : "bg-blue-600") : "bg-white/5")} />
                  ))}
                </div>
              </div>
              <div className="flex flex-col items-center justify-center text-center z-10 w-full px-4">
                <div className="flex items-center justify-center gap-1 mb-1">
                   <div className="w-1.5 h-3 bg-blue-600" />
                   <div className="w-1.5 h-3 bg-blue-400" />
                   <div className="w-1.5 h-3 bg-red-600" />
                </div>
                <span className="text-9xl font-black italic tracking-tighter text-white leading-none text-center block w-full drop-shadow-[0_0_40px_rgba(59,130,246,0.3)]">{speed}</span>
                <span className="text-[10px] font-black text-zinc-500 uppercase tracking-[0.4em] mt-2 italic text-center">M PERFORMANCE</span>
                <div className="mt-4 flex gap-2 justify-center">
                   <Badge className="bg-blue-600/20 text-blue-400 border-blue-500/30 text-[9px] font-bold">SPORT+</Badge>
                   <Badge className="bg-red-600/20 text-red-500 border-red-500/30 text-[9px] font-bold italic">M</Badge>
                </div>
              </div>
            </div>
          )}
          {theme === 'rs_performance' && (
            <div className="w-full h-full relative flex items-center justify-center bg-[#080808] rounded-[3.5rem] border border-white/10 overflow-hidden">
              <div className="absolute top-8 left-10 right-10 h-1.5 flex gap-1">
                {[...Array(25)].map((_, i) => (
                  <div key={i} className={cn("flex-1 h-full transition-all duration-150", (i / 25) * 320 <= speed ? (i > 20 ? "bg-red-600 shadow-[0_0_15px_red]" : "bg-white") : "bg-white/5")} />
                ))}
              </div>
              <div className="flex flex-col items-center">
                <span className="text-[10px] font-black text-red-600 tracking-[0.6em] mb-4">RS</span>
                <span className="text-8xl font-black text-white leading-none tracking-tighter drop-shadow-[0_0_30px_rgba(255,255,255,0.1)]">{speed}</span>
                <div className="flex flex-col items-center gap-1 mt-6">
                  <span className="text-[8px] font-black text-zinc-500 tracking-[0.5em] uppercase">QUATTRO</span>
                  <div className="h-0.5 w-12 bg-red-600" />
                </div>
              </div>
            </div>
          )}
          {theme === 'amg_performance' && (
            <div className="w-full h-full relative flex items-center justify-center bg-black rounded-[3rem] border border-zinc-800 overflow-hidden shadow-2xl">
               <svg className="absolute inset-0 w-full h-full p-8" viewBox="0 0 100 100">
                <circle cx="50" cy="50" r="44" fill="none" stroke="rgba(255,255,0,0.05)" strokeWidth="2.5" strokeDasharray="230 360" strokeLinecap="round" transform="rotate(125 50 50)" />
                <circle cx="50" cy="50" r="44" fill="none" stroke={speed > 280 ? "#ef4444" : "#eab308"} strokeWidth="3.5" strokeDasharray={`${(speed / 350) * 230} 360`} strokeLinecap="round" transform="rotate(125 50 50)" className="transition-all duration-300 shadow-[0_0_20px_rgba(234,179,8,0.5)]" />
              </svg>
              <div className="flex flex-col items-center z-10">
                <span className="text-[12px] font-black text-zinc-500 tracking-[0.6em] mb-4 italic">AMG</span>
                <span className="text-9xl font-black text-white leading-none tracking-tighter drop-shadow-[0_10px_20px_rgba(0,0,0,1)]">{speed}</span>
                <div className="mt-6 flex items-center gap-3">
                   <div className="px-3 py-0.5 bg-yellow-500 text-black text-[9px] font-black italic rounded-sm">RACE</div>
                   <span className="text-[10px] font-bold text-yellow-500 tracking-widest">S+</span>
                </div>
              </div>
            </div>
          )}
          {theme === 'porsche' && (
            <div className="w-full h-full relative flex items-center justify-center bg-zinc-900 rounded-full border-[10px] border-zinc-800 shadow-[0_30px_60px_rgba(0,0,0,0.5),inset_0_0_40px_rgba(255,255,255,0.05)]">
              {[...Array(31)].map((_, i) => {
                const angle = -140 + (i * 9.3);
                return (
                  <div key={i} className={cn("absolute w-0.5 h-4 bg-zinc-700 origin-bottom bottom-1/2 left-1/2 -translate-x-1/2", i % 5 === 0 && "h-6 w-1 bg-white")} style={{ transform: `translateX(-50%) rotate(${angle}deg) translateY(-135px)` }} />
                )
              })}
              <div className="absolute w-1.5 h-[150px] bg-red-600 origin-bottom bottom-1/2 left-1/2 -translate-x-1/2 transition-transform duration-300 ease-out z-20 rounded-full shadow-[0_0_15px_red]" style={{ transform: `translateX(-50%) rotate(${-140 + (Math.min(speed, 350) / 350) * 280}deg)` }} />
              <div className="absolute bottom-1/2 left-1/2 -translate-x-1/2 translate-y-1/2 w-6 h-6 bg-black rounded-full z-30 border-2 border-zinc-700" />
              <div className="flex flex-col items-center z-10 translate-y-20 bg-black/90 px-8 py-3 rounded-2xl border border-white/10 shadow-2xl">
                <span className="text-5xl font-black text-white leading-none tracking-tight">{speed}</span>
                <span className="text-[8px] font-black text-red-600 uppercase tracking-[0.4em] mt-1 italic">GT3 RS</span>
              </div>
            </div>
          )}
          {theme === 'default' && (
            <div className="relative w-64 h-64 flex items-center justify-center">
              <div className="absolute inset-0 rounded-full border-[10px] border-white/5 border-t-accent border-r-accent/40 transition-transform duration-300" style={{ transform: `rotate(${135 + (Math.min(speed, 300) / 300) * 270}deg)` }} />
              <div className="flex flex-col items-center z-10">
                <span className="text-7xl font-black italic tracking-tighter neon-text">{speed}</span>
                <span className="text-[10px] font-bold tracking-[0.2em] text-muted-foreground uppercase">km/h</span>
              </div>
            </div>
          )}
        </div>

        <div className="w-full mt-4">
          <Button onClick={() => { if (isDriving) { setShowSummary(true); setIsDriving(false); } else { setTripTime(0); setTripDistance(0); setBrakeCount(0); setPeakSpeed(0); setAiSummary(null); setStartTime(new Date()); setIsDriving(true); } }} className={cn("w-full h-16 rounded-2xl font-black text-lg uppercase italic tracking-tighter transition-all duration-500 shadow-xl", isDriving ? "bg-red-500 hover:bg-red-600 text-white" : "bg-accent hover:bg-accent/80 text-background neon-glow")}>
            {isDriving ? "NDALO MATJEN" : "FILLO MATJEN"}
          </Button>
        </div>

        <div className="grid grid-cols-2 gap-3 w-full mt-6">
          <Card className="glass border-white/5 p-4 flex flex-col items-center justify-center gap-2 rounded-2xl">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Clock className="w-3 h-3 text-accent" />
              <span className="text-[9px] font-black uppercase tracking-widest">KOHA E TRIPIT</span>
            </div>
            <span className="text-xl font-black italic">{formatTime(tripTime)}</span>
          </Card>
          <Card className="glass border-white/5 p-4 flex flex-col items-center justify-center gap-2 rounded-2xl">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Navigation className="w-3 h-3 text-accent" />
              <span className="text-[9px] font-black uppercase tracking-widest">DISTANCA (KM)</span>
            </div>
            <span className="text-xl font-black italic">{(tripDistance / 1000).toFixed(2)}</span>
          </Card>
          <Card className="glass border-white/5 p-4 flex flex-col items-center justify-center gap-2 rounded-2xl">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Footprints className="w-3 h-3 text-red-500" />
              <span className="text-[9px] font-black uppercase tracking-widest">FRENIME</span>
            </div>
            <span className="text-xl font-black italic">{brakeCount}</span>
          </Card>
          <Card className="glass border-white/5 p-4 flex flex-col items-center justify-center gap-2 rounded-2xl">
            <div className="flex items-center gap-2 text-muted-foreground">
              <Zap className="w-3 h-3 text-yellow-500" />
              <span className="text-[9px] font-black uppercase tracking-widest">TOP SPEED</span>
            </div>
            <span className="text-xl font-black italic text-accent">{peakSpeed} <span className="text-[10px]">km/h</span></span>
          </Card>
        </div>

        <div className="w-full mt-3">
          {nearestAlert ? (
            <div className="glass rounded-2xl p-4 border-red-500/30 animate-pulse-glow bg-red-500/5">
              <div className="flex items-center gap-3">
                <AlertTriangle className="text-red-500 w-6 h-6" />
                <div className="flex-1">
                  <p className="text-[9px] font-black text-red-500 uppercase tracking-widest">KUJDES: {nearestAlert.type.toUpperCase()} AFËR</p>
                  <p className="text-xs font-bold truncate">{nearestAlert.location}</p>
                  <p className="text-[9px] font-bold text-muted-foreground">DISTANCA: {Math.round(nearestAlert.distance)} METRA</p>
                </div>
              </div>
            </div>
          ) : (
            <div className="glass rounded-2xl p-4 border-accent/20 flex items-center gap-3">
              <Radio className="text-accent w-6 h-6" />
              <div>
                <p className="text-[9px] font-black text-accent uppercase tracking-widest">RRUGËT E KOSOVËS: E PASTRË</p>
                <p className="text-xs font-bold">Nuk u detektua asnjë radar afër.</p>
              </div>
            </div>
          )}
        </div>
      </div>

      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="glass border-white/10 sm:max-w-md max-h-[90vh] overflow-y-auto no-scrollbar rounded-[2.5rem]">
          <DialogHeader className="flex flex-col items-center gap-2 pb-4">
            <div className="w-16 h-16 bg-accent/20 rounded-full flex items-center justify-center mb-2">
              <CheckCircle2 className="w-8 h-8 text-accent" />
            </div>
            <DialogTitle className="text-2xl font-black italic uppercase tracking-tighter text-center">PERFORMANCA E GARËS</DialogTitle>
            <div className="flex items-center gap-2 mt-1">
              <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">STATISTIKAT E FUNDIT</p>
              {recordStatus && (
                <Badge className="bg-yellow-500 text-black font-black italic text-[8px] animate-bounce">
                  <Trophy className="w-2.5 h-2.5 mr-1" />
                  {recordStatus}
                </Badge>
              )}
            </div>
          </DialogHeader>

          <div className="grid grid-cols-2 gap-4">
            <Card className="bg-white/5 border-white/5 p-4 flex flex-col items-center rounded-2xl">
              <span className="text-[9px] font-black text-muted-foreground uppercase">KOHA</span>
              <span className="text-xl font-black italic">{formatTime(tripTime)}</span>
            </Card>
            <Card className="bg-white/5 border-white/5 p-4 flex flex-col items-center rounded-2xl">
              <span className="text-[9px] font-black text-muted-foreground uppercase">DISTANCA</span>
              <span className="text-xl font-black italic">{(tripDistance / 1000).toFixed(2)} km</span>
            </Card>
            <Card className="bg-white/5 border-white/5 p-4 flex flex-col items-center rounded-2xl">
              <span className="text-[9px] font-black text-muted-foreground uppercase">TOP SPEED</span>
              <span className="text-xl font-black italic text-accent">{peakSpeed} km/h</span>
            </Card>
            <Card className="bg-white/5 border-white/5 p-4 flex flex-col items-center rounded-2xl">
              <span className="text-[9px] font-black text-muted-foreground uppercase">FRENIME</span>
              <span className="text-xl font-black italic">{brakeCount}</span>
            </Card>
          </div>

          <div className="mt-6 space-y-4">
            {!aiSummary && !isGeneratingAi ? (
              <Button onClick={generateAiAnalysis} className="w-full h-14 bg-gradient-to-r from-accent/80 to-blue-600 rounded-2xl font-black italic uppercase text-sm shadow-xl neon-glow flex items-center gap-2">
                <Sparkles className="w-4 h-4" />
                GJENERO ANALIZËN ME AI
              </Button>
            ) : isGeneratingAi ? (
              <div className="flex flex-col items-center gap-3 p-6 glass rounded-2xl animate-pulse">
                <Loader2 className="w-6 h-6 animate-spin text-accent" />
                <p className="text-[10px] font-black uppercase italic">Duke analizuar telemetrinë tuaj...</p>
              </div>
            ) : (
              <Card className="p-5 glass border-accent/20 rounded-2xl space-y-3">
                <div className="flex items-center gap-2">
                  <Sparkles className="w-4 h-4 text-accent" />
                  <span className="text-[10px] font-black uppercase text-accent">KËSHILLË NGA DRIVE-AI</span>
                </div>
                <p className="text-xs font-medium leading-relaxed text-zinc-200 italic">
                  {aiSummary}
                </p>
              </Card>
            )}
          </div>

          <DialogFooter className="mt-6 flex gap-2">
            <Button variant="outline" className="flex-1 rounded-xl h-12 font-black italic uppercase text-[10px] glass border-white/10" disabled={isSaving} onClick={handleSaveRun}>
              {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ"}
            </Button>
            <Button className="flex-1 bg-accent text-background rounded-xl h-12 font-black italic uppercase text-[10px]" onClick={() => setShowSummary(false)}>
              MBYLL
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}